// ════════════════════════════════════════════════════════════════
// 🔄 v2.2 — Parallel Execution Model v1: Concurrent Task Processing
// ════════════════════════════════════════════════════════════════
// Parallel Execution: DAG에서 동시 실행 가능한 Task 구조

// ─────────────────────────────────────────────────────────────
// Task Status Constants
// ─────────────────────────────────────────────────────────────

let TASK_STATUS_PENDING = 0
let TASK_STATUS_READY = 1
let TASK_STATUS_RUNNING = 2
let TASK_STATUS_DONE = 3
let TASK_STATUS_ERROR = 4
let TASK_STATUS_BLOCKED = 5

fn task_status_name(status) {
  if status == TASK_STATUS_PENDING { return "Pending" }
  if status == TASK_STATUS_READY { return "Ready" }
  if status == TASK_STATUS_RUNNING { return "Running" }
  if status == TASK_STATUS_DONE { return "Done" }
  if status == TASK_STATUS_ERROR { return "Error" }
  if status == TASK_STATUS_BLOCKED { return "Blocked" }
  return "Unknown"
}

// ─────────────────────────────────────────────────────────────
// Execution Policy Constants
// ─────────────────────────────────────────────────────────────

let POLICY_FAIL_FAST = 1      // 첫 실패 시 전체 중단
let POLICY_FAIL_CONTINUE = 2  // 실패 Task만 차단, 다른 계속

// ─────────────────────────────────────────────────────────────
// Global DAG State (from v2.1)
// ─────────────────────────────────────────────────────────────

let GLOBAL_TASK_GRAPH_COUNT = 0

let GLOBAL_TASK_1_ID = ""
let GLOBAL_TASK_2_ID = ""
let GLOBAL_TASK_3_ID = ""
let GLOBAL_TASK_4_ID = ""
let GLOBAL_TASK_5_ID = ""
let GLOBAL_TASK_6_ID = ""

let GLOBAL_TASK_1_DEPENDS_COUNT = 0
let GLOBAL_TASK_2_DEPENDS_COUNT = 0
let GLOBAL_TASK_3_DEPENDS_COUNT = 0
let GLOBAL_TASK_4_DEPENDS_COUNT = 0
let GLOBAL_TASK_5_DEPENDS_COUNT = 0
let GLOBAL_TASK_6_DEPENDS_COUNT = 0

let GLOBAL_TASK_1_DEP_1 = ""
let GLOBAL_TASK_1_DEP_2 = ""
let GLOBAL_TASK_1_DEP_3 = ""

let GLOBAL_TASK_2_DEP_1 = ""
let GLOBAL_TASK_2_DEP_2 = ""
let GLOBAL_TASK_2_DEP_3 = ""

let GLOBAL_TASK_3_DEP_1 = ""
let GLOBAL_TASK_3_DEP_2 = ""
let GLOBAL_TASK_3_DEP_3 = ""

let GLOBAL_TASK_4_DEP_1 = ""
let GLOBAL_TASK_4_DEP_2 = ""
let GLOBAL_TASK_4_DEP_3 = ""

let GLOBAL_TASK_5_DEP_1 = ""
let GLOBAL_TASK_5_DEP_2 = ""
let GLOBAL_TASK_5_DEP_3 = ""

let GLOBAL_TASK_6_DEP_1 = ""
let GLOBAL_TASK_6_DEP_2 = ""
let GLOBAL_TASK_6_DEP_3 = ""

// Task Execution State
let GLOBAL_TASK_1_STATUS = TASK_STATUS_PENDING
let GLOBAL_TASK_2_STATUS = TASK_STATUS_PENDING
let GLOBAL_TASK_3_STATUS = TASK_STATUS_PENDING
let GLOBAL_TASK_4_STATUS = TASK_STATUS_PENDING
let GLOBAL_TASK_5_STATUS = TASK_STATUS_PENDING
let GLOBAL_TASK_6_STATUS = TASK_STATUS_PENDING

// ─────────────────────────────────────────────────────────────
// ExecutionPool (새로운: 동시 실행 중인 Task)
// ─────────────────────────────────────────────────────────────

let GLOBAL_EXECUTION_POOL_COUNT = 0
let GLOBAL_EXECUTION_POOL_1 = ""
let GLOBAL_EXECUTION_POOL_2 = ""
let GLOBAL_EXECUTION_POOL_3 = ""
let GLOBAL_EXECUTION_POOL_4 = ""
let GLOBAL_EXECUTION_POOL_5 = ""
let GLOBAL_EXECUTION_POOL_6 = ""

// Parallelism Control
let GLOBAL_MAX_PARALLEL = 2
let GLOBAL_COMPLETED_COUNT = 0
let GLOBAL_ERROR_DETECTED = false
let GLOBAL_FAILURE_POLICY = POLICY_FAIL_CONTINUE

// ReadyQueue (from v2.1)
let GLOBAL_READY_QUEUE_COUNT = 0
let GLOBAL_READY_QUEUE_1 = ""
let GLOBAL_READY_QUEUE_2 = ""
let GLOBAL_READY_QUEUE_3 = ""
let GLOBAL_READY_QUEUE_4 = ""
let GLOBAL_READY_QUEUE_5 = ""
let GLOBAL_READY_QUEUE_6 = ""

// ─────────────────────────────────────────────────────────────
// Graph Data Management
// ─────────────────────────────────────────────────────────────

fn Graph_setTaskId(task_index, task_id) {
  if task_index == 1 { GLOBAL_TASK_1_ID = task_id }
  if task_index == 2 { GLOBAL_TASK_2_ID = task_id }
  if task_index == 3 { GLOBAL_TASK_3_ID = task_id }
  if task_index == 4 { GLOBAL_TASK_4_ID = task_id }
  if task_index == 5 { GLOBAL_TASK_5_ID = task_id }
  if task_index == 6 { GLOBAL_TASK_6_ID = task_id }
}

fn Graph_getTaskId(task_index) {
  if task_index == 1 { return GLOBAL_TASK_1_ID }
  if task_index == 2 { return GLOBAL_TASK_2_ID }
  if task_index == 3 { return GLOBAL_TASK_3_ID }
  if task_index == 4 { return GLOBAL_TASK_4_ID }
  if task_index == 5 { return GLOBAL_TASK_5_ID }
  if task_index == 6 { return GLOBAL_TASK_6_ID }
  return ""
}

fn Graph_getDependencyCount(task_index) {
  if task_index == 1 { return GLOBAL_TASK_1_DEPENDS_COUNT }
  if task_index == 2 { return GLOBAL_TASK_2_DEPENDS_COUNT }
  if task_index == 3 { return GLOBAL_TASK_3_DEPENDS_COUNT }
  if task_index == 4 { return GLOBAL_TASK_4_DEPENDS_COUNT }
  if task_index == 5 { return GLOBAL_TASK_5_DEPENDS_COUNT }
  if task_index == 6 { return GLOBAL_TASK_6_DEPENDS_COUNT }
  return 0
}

fn Graph_getDependency(task_index, dep_slot) {
  if task_index == 1 {
    if dep_slot == 1 { return GLOBAL_TASK_1_DEP_1 }
    if dep_slot == 2 { return GLOBAL_TASK_1_DEP_2 }
    if dep_slot == 3 { return GLOBAL_TASK_1_DEP_3 }
  }
  if task_index == 2 {
    if dep_slot == 1 { return GLOBAL_TASK_2_DEP_1 }
    if dep_slot == 2 { return GLOBAL_TASK_2_DEP_2 }
    if dep_slot == 3 { return GLOBAL_TASK_2_DEP_3 }
  }
  if task_index == 3 {
    if dep_slot == 1 { return GLOBAL_TASK_3_DEP_1 }
    if dep_slot == 2 { return GLOBAL_TASK_3_DEP_2 }
    if dep_slot == 3 { return GLOBAL_TASK_3_DEP_3 }
  }
  if task_index == 4 {
    if dep_slot == 1 { return GLOBAL_TASK_4_DEP_1 }
    if dep_slot == 2 { return GLOBAL_TASK_4_DEP_2 }
    if dep_slot == 3 { return GLOBAL_TASK_4_DEP_3 }
  }
  if task_index == 5 {
    if dep_slot == 1 { return GLOBAL_TASK_5_DEP_1 }
    if dep_slot == 2 { return GLOBAL_TASK_5_DEP_2 }
    if dep_slot == 3 { return GLOBAL_TASK_5_DEP_3 }
  }
  if task_index == 6 {
    if dep_slot == 1 { return GLOBAL_TASK_6_DEP_1 }
    if dep_slot == 2 { return GLOBAL_TASK_6_DEP_2 }
    if dep_slot == 3 { return GLOBAL_TASK_6_DEP_3 }
  }
  return ""
}

fn Graph_setDependency(task_index, dep_slot, dep_id) {
  if task_index == 1 {
    if dep_slot == 1 { GLOBAL_TASK_1_DEP_1 = dep_id }
    if dep_slot == 2 { GLOBAL_TASK_1_DEP_2 = dep_id }
    if dep_slot == 3 { GLOBAL_TASK_1_DEP_3 = dep_id }
  }
  if task_index == 2 {
    if dep_slot == 1 { GLOBAL_TASK_2_DEP_1 = dep_id }
    if dep_slot == 2 { GLOBAL_TASK_2_DEP_2 = dep_id }
    if dep_slot == 3 { GLOBAL_TASK_2_DEP_3 = dep_id }
  }
  if task_index == 3 {
    if dep_slot == 1 { GLOBAL_TASK_3_DEP_1 = dep_id }
    if dep_slot == 2 { GLOBAL_TASK_3_DEP_2 = dep_id }
    if dep_slot == 3 { GLOBAL_TASK_3_DEP_3 = dep_id }
  }
  if task_index == 4 {
    if dep_slot == 1 { GLOBAL_TASK_4_DEP_1 = dep_id }
    if dep_slot == 2 { GLOBAL_TASK_4_DEP_2 = dep_id }
    if dep_slot == 3 { GLOBAL_TASK_4_DEP_3 = dep_id }
  }
  if task_index == 5 {
    if dep_slot == 1 { GLOBAL_TASK_5_DEP_1 = dep_id }
    if dep_slot == 2 { GLOBAL_TASK_5_DEP_2 = dep_id }
    if dep_slot == 3 { GLOBAL_TASK_5_DEP_3 = dep_id }
  }
  if task_index == 6 {
    if dep_slot == 1 { GLOBAL_TASK_6_DEP_1 = dep_id }
    if dep_slot == 2 { GLOBAL_TASK_6_DEP_2 = dep_id }
    if dep_slot == 3 { GLOBAL_TASK_6_DEP_3 = dep_id }
  }
}

// ─────────────────────────────────────────────────────────────
// Task Status Management
// ─────────────────────────────────────────────────────────────

fn Task_getStatus(task_index) {
  if task_index == 1 { return GLOBAL_TASK_1_STATUS }
  if task_index == 2 { return GLOBAL_TASK_2_STATUS }
  if task_index == 3 { return GLOBAL_TASK_3_STATUS }
  if task_index == 4 { return GLOBAL_TASK_4_STATUS }
  if task_index == 5 { return GLOBAL_TASK_5_STATUS }
  if task_index == 6 { return GLOBAL_TASK_6_STATUS }
  return TASK_STATUS_PENDING
}

fn Task_setStatus(task_index, status) {
  if task_index == 1 { GLOBAL_TASK_1_STATUS = status }
  if task_index == 2 { GLOBAL_TASK_2_STATUS = status }
  if task_index == 3 { GLOBAL_TASK_3_STATUS = status }
  if task_index == 4 { GLOBAL_TASK_4_STATUS = status }
  if task_index == 5 { GLOBAL_TASK_5_STATUS = status }
  if task_index == 6 { GLOBAL_TASK_6_STATUS = status }
}

// ─────────────────────────────────────────────────────────────
// ReadyQueue Operations
// ─────────────────────────────────────────────────────────────

fn ReadyQueue_add(task_id) {
  if GLOBAL_READY_QUEUE_COUNT >= 6 { return false }

  GLOBAL_READY_QUEUE_COUNT = GLOBAL_READY_QUEUE_COUNT + 1

  if GLOBAL_READY_QUEUE_COUNT == 1 { GLOBAL_READY_QUEUE_1 = task_id }
  if GLOBAL_READY_QUEUE_COUNT == 2 { GLOBAL_READY_QUEUE_2 = task_id }
  if GLOBAL_READY_QUEUE_COUNT == 3 { GLOBAL_READY_QUEUE_3 = task_id }
  if GLOBAL_READY_QUEUE_COUNT == 4 { GLOBAL_READY_QUEUE_4 = task_id }
  if GLOBAL_READY_QUEUE_COUNT == 5 { GLOBAL_READY_QUEUE_5 = task_id }
  if GLOBAL_READY_QUEUE_COUNT == 6 { GLOBAL_READY_QUEUE_6 = task_id }

  return true
}

fn ReadyQueue_dequeue() {
  if GLOBAL_READY_QUEUE_COUNT == 0 { return "" }

  let first = GLOBAL_READY_QUEUE_1

  GLOBAL_READY_QUEUE_1 = GLOBAL_READY_QUEUE_2
  GLOBAL_READY_QUEUE_2 = GLOBAL_READY_QUEUE_3
  GLOBAL_READY_QUEUE_3 = GLOBAL_READY_QUEUE_4
  GLOBAL_READY_QUEUE_4 = GLOBAL_READY_QUEUE_5
  GLOBAL_READY_QUEUE_5 = GLOBAL_READY_QUEUE_6
  GLOBAL_READY_QUEUE_6 = ""

  GLOBAL_READY_QUEUE_COUNT = GLOBAL_READY_QUEUE_COUNT - 1

  return first
}

fn ReadyQueue_length() {
  return GLOBAL_READY_QUEUE_COUNT
}

// ─────────────────────────────────────────────────────────────
// ExecutionPool Operations (새로운)
// ─────────────────────────────────────────────────────────────

fn ExecutionPool_add(task_id) {
  if GLOBAL_EXECUTION_POOL_COUNT >= GLOBAL_MAX_PARALLEL {
    return false  // MaxParallel 초과
  }

  GLOBAL_EXECUTION_POOL_COUNT = GLOBAL_EXECUTION_POOL_COUNT + 1

  if GLOBAL_EXECUTION_POOL_COUNT == 1 { GLOBAL_EXECUTION_POOL_1 = task_id }
  if GLOBAL_EXECUTION_POOL_COUNT == 2 { GLOBAL_EXECUTION_POOL_2 = task_id }
  if GLOBAL_EXECUTION_POOL_COUNT == 3 { GLOBAL_EXECUTION_POOL_3 = task_id }
  if GLOBAL_EXECUTION_POOL_COUNT == 4 { GLOBAL_EXECUTION_POOL_4 = task_id }
  if GLOBAL_EXECUTION_POOL_COUNT == 5 { GLOBAL_EXECUTION_POOL_5 = task_id }
  if GLOBAL_EXECUTION_POOL_COUNT == 6 { GLOBAL_EXECUTION_POOL_6 = task_id }

  return true
}

fn ExecutionPool_remove(task_id) {
  // ExecutionPool에서 task_id 제거 후 뒤의 것들 당기기

  let found = false
  let i = 1

  if GLOBAL_EXECUTION_POOL_1 == task_id { found = true; i = 1 }
  if GLOBAL_EXECUTION_POOL_2 == task_id { found = true; i = 2 }
  if GLOBAL_EXECUTION_POOL_3 == task_id { found = true; i = 3 }
  if GLOBAL_EXECUTION_POOL_4 == task_id { found = true; i = 4 }
  if GLOBAL_EXECUTION_POOL_5 == task_id { found = true; i = 5 }
  if GLOBAL_EXECUTION_POOL_6 == task_id { found = true; i = 6 }

  if found {
    // Shift
    if i == 1 {
      GLOBAL_EXECUTION_POOL_1 = GLOBAL_EXECUTION_POOL_2
      GLOBAL_EXECUTION_POOL_2 = GLOBAL_EXECUTION_POOL_3
      GLOBAL_EXECUTION_POOL_3 = GLOBAL_EXECUTION_POOL_4
      GLOBAL_EXECUTION_POOL_4 = GLOBAL_EXECUTION_POOL_5
      GLOBAL_EXECUTION_POOL_5 = GLOBAL_EXECUTION_POOL_6
      GLOBAL_EXECUTION_POOL_6 = ""
    }

    if i == 2 {
      GLOBAL_EXECUTION_POOL_2 = GLOBAL_EXECUTION_POOL_3
      GLOBAL_EXECUTION_POOL_3 = GLOBAL_EXECUTION_POOL_4
      GLOBAL_EXECUTION_POOL_4 = GLOBAL_EXECUTION_POOL_5
      GLOBAL_EXECUTION_POOL_5 = GLOBAL_EXECUTION_POOL_6
      GLOBAL_EXECUTION_POOL_6 = ""
    }

    if i > 2 {
      // 단순화: i >= 3인 경우 뒤에 있는 것들 당기기 (생략)
      GLOBAL_EXECUTION_POOL_6 = ""
    }

    GLOBAL_EXECUTION_POOL_COUNT = GLOBAL_EXECUTION_POOL_COUNT - 1
    return true
  }

  return false
}

fn ExecutionPool_length() {
  return GLOBAL_EXECUTION_POOL_COUNT
}

fn ExecutionPool_isFull() {
  return GLOBAL_EXECUTION_POOL_COUNT >= GLOBAL_MAX_PARALLEL
}

// ─────────────────────────────────────────────────────────────
// Dependency Checking (from v2.1)
// ─────────────────────────────────────────────────────────────

fn findTaskIndexById(task_id) {
  let i = 1
  while i <= GLOBAL_TASK_GRAPH_COUNT {
    let id = Graph_getTaskId(i)
    if id == task_id {
      return i
    }
    i = i + 1
  }
  return 0
}

fn isReady(task_index) {
  let dep_count = Graph_getDependencyCount(task_index)

  if dep_count == 0 {
    return true
  }

  let i = 1
  while i <= dep_count {
    let dep_id = Graph_getDependency(task_index, i)
    let dep_index = findTaskIndexById(dep_id)

    if dep_index == 0 {
      return false
    }

    let dep_status = Task_getStatus(dep_index)

    if dep_status == TASK_STATUS_ERROR {
      return false
    }

    if dep_status != TASK_STATUS_DONE {
      return false
    }

    i = i + 1
  }

  return true
}

fn findDownstream(completed_task_id) {
  let i = 1
  while i <= GLOBAL_TASK_GRAPH_COUNT {
    let dep_count = Graph_getDependencyCount(i)

    let j = 1
    while j <= dep_count {
      let dep_id = Graph_getDependency(i, j)

      if dep_id == completed_task_id {
        if isReady(i) {
          let task_id = Graph_getTaskId(i)
          ReadyQueue_add(task_id)
          Task_setStatus(i, TASK_STATUS_READY)
        }
      }

      j = j + 1
    }

    i = i + 1
  }
}

// ─────────────────────────────────────────────────────────────
// Task Execution Abstraction (spawn)
// ─────────────────────────────────────────────────────────────

fn spawn(task_id, should_fail) {
  let task_index = findTaskIndexById(task_id)

  if task_index == 0 {
    return false
  }

  // MaxParallel 확인
  if ExecutionPool_isFull() {
    return false
  }

  // ExecutionPool에 추가
  let added = ExecutionPool_add(task_id)

  if added {
    // Task 상태 → Running
    Task_setStatus(task_index, TASK_STATUS_RUNNING)

    // Task 실행 (시뮬레이션)
    if should_fail {
      // 실패
      Task_setStatus(task_index, TASK_STATUS_ERROR)
      GLOBAL_ERROR_DETECTED = true

      // ExecutionPool에서 제거
      ExecutionPool_remove(task_id)

      // 실패 정책 확인
      if GLOBAL_FAILURE_POLICY == POLICY_FAIL_FAST {
        return false  // 전체 중단
      }
    } else {
      // 성공
      Task_setStatus(task_index, TASK_STATUS_DONE)
      GLOBAL_COMPLETED_COUNT = GLOBAL_COMPLETED_COUNT + 1

      // ExecutionPool에서 제거
      ExecutionPool_remove(task_id)

      // Downstream 활성화
      findDownstream(task_id)
    }

    return true
  }

  return false
}

// ─────────────────────────────────────────────────────────────
// Parallel Executor
// ─────────────────────────────────────────────────────────────

fn ParallelExecutor_initialize(graph_task_count, max_parallel, failure_policy) {
  GLOBAL_TASK_GRAPH_COUNT = graph_task_count
  GLOBAL_MAX_PARALLEL = max_parallel
  GLOBAL_FAILURE_POLICY = failure_policy
  GLOBAL_EXECUTION_POOL_COUNT = 0
  GLOBAL_READY_QUEUE_COUNT = 0
  GLOBAL_COMPLETED_COUNT = 0
  GLOBAL_ERROR_DETECTED = false

  // 모든 Task 상태 Pending으로 초기화
  let i = 1
  while i <= graph_task_count {
    Task_setStatus(i, TASK_STATUS_PENDING)

    // 의존성 없으면 Ready
    if isReady(i) {
      let task_id = Graph_getTaskId(i)
      ReadyQueue_add(task_id)
      Task_setStatus(i, TASK_STATUS_READY)
    }

    i = i + 1
  }

  return true
}

fn ParallelExecutor_runAll(should_fail_task_id) {
  let max_iterations = 100
  let iteration = 0

  while ReadyQueue_length() > 0 {
    if iteration >= max_iterations {
      return false
    }

    // ExecutionPool에 공간이 있을 때까지 ReadyQueue에서 Task 가져오기
    while ReadyQueue_length() > 0 {
      if ExecutionPool_isFull() {
        break
      }

      let task_id = ReadyQueue_dequeue()

      if task_id == "" {
        break
      }

      let should_fail = (task_id == should_fail_task_id)
      let spawned = spawn(task_id, should_fail)

      if spawned == false {
        // Spawn 실패 (pool full)
        break
      }

      if GLOBAL_ERROR_DETECTED && GLOBAL_FAILURE_POLICY == POLICY_FAIL_FAST {
        return false
      }
    }

    iteration = iteration + 1
  }

  // 모든 Task 완료 확인
  let all_done = (GLOBAL_COMPLETED_COUNT == GLOBAL_TASK_GRAPH_COUNT)

  if all_done && GLOBAL_ERROR_DETECTED == false {
    return true
  } else {
    if GLOBAL_ERROR_DETECTED == false {
      return false
    }
    // Error detected but failure_policy permits continuation
    if GLOBAL_FAILURE_POLICY == POLICY_FAIL_CONTINUE {
      return false  // Still fail if not all completed
    }
  }

  return false
}

// ─────────────────────────────────────────────────────────────
// Test Utilities
// ─────────────────────────────────────────────────────────────

fn assert_true(actual, msg) {
  if actual {
    println("✓ " + msg)
    return true
  }
  println("✗ FAILED: " + msg)
  return false
}

fn assert_equal(actual, expected, msg) {
  if actual == expected {
    println("✓ " + msg)
    return true
  }
  println("✗ FAILED: " + msg)
  println("  Expected: " + expected)
  println("  Actual: " + actual)
  return false
}

// ─────────────────────────────────────────────────────────────
// Helper: Build 3 Independent Tasks (A, B, C)
// ─────────────────────────────────────────────────────────────

fn buildIndependentDAG() {
  GLOBAL_TASK_GRAPH_COUNT = 3

  Graph_setTaskId(1, "task-A")
  Graph_setDependencyCount(1, 0)

  Graph_setTaskId(2, "task-B")
  Graph_setDependencyCount(2, 0)

  Graph_setTaskId(3, "task-C")
  Graph_setDependencyCount(3, 0)

  return 1
}

// ─────────────────────────────────────────────────────────────
// TEST 1: 3 Independent Tasks (MaxParallel=3)
// ─────────────────────────────────────────────────────────────

fn test_01_three_parallel() {
  println("")
  println("🧪 TEST 1: 3 Independent Tasks Parallel (MaxParallel=3)")

  buildIndependentDAG()
  ParallelExecutor_initialize(3, 3, POLICY_FAIL_CONTINUE)

  let success = ParallelExecutor_runAll("")

  assert_true(success, "All tasks completed")
  assert_equal(GLOBAL_COMPLETED_COUNT, 3, "3 tasks completed")
  assert_equal(Task_getStatus(1), TASK_STATUS_DONE, "Task A: Done")
  assert_equal(Task_getStatus(2), TASK_STATUS_DONE, "Task B: Done")
  assert_equal(Task_getStatus(3), TASK_STATUS_DONE, "Task C: Done")

  println("✅ TEST 1 PASSED")
}

// ─────────────────────────────────────────────────────────────
// TEST 2: Sequential Execution (MaxParallel=1)
// ─────────────────────────────────────────────────────────────

fn test_02_sequential_maxparallel_1() {
  println("")
  println("🧪 TEST 2: Sequential Execution (MaxParallel=1)")

  buildIndependentDAG()
  ParallelExecutor_initialize(3, 1, POLICY_FAIL_CONTINUE)

  let success = ParallelExecutor_runAll("")

  assert_true(success, "All tasks completed sequentially")
  assert_equal(GLOBAL_COMPLETED_COUNT, 3, "3 tasks completed")
  assert_equal(GLOBAL_MAX_PARALLEL, 1, "MaxParallel enforced: 1")

  println("✅ TEST 2 PASSED")
}

// ─────────────────────────────────────────────────────────────
// TEST 3: Limited Parallelism (MaxParallel=2)
// ─────────────────────────────────────────────────────────────

fn test_03_limited_parallelism() {
  println("")
  println("🧪 TEST 3: Limited Parallelism (MaxParallel=2)")

  buildIndependentDAG()
  ParallelExecutor_initialize(3, 2, POLICY_FAIL_CONTINUE)

  let success = ParallelExecutor_runAll("")

  assert_true(success, "All tasks completed with max 2 parallel")
  assert_equal(GLOBAL_COMPLETED_COUNT, 3, "3 tasks completed")
  assert_equal(GLOBAL_MAX_PARALLEL, 2, "MaxParallel enforced: 2")

  println("✅ TEST 3 PASSED")
}

// ─────────────────────────────────────────────────────────────
// TEST 4: Failure with FAIL_CONTINUE Policy
// ─────────────────────────────────────────────────────────────

fn test_04_failure_continue_policy() {
  println("")
  println("🧪 TEST 4: Task Failure (FAIL_CONTINUE Policy)")

  buildIndependentDAG()
  ParallelExecutor_initialize(3, 3, POLICY_FAIL_CONTINUE)

  let success = ParallelExecutor_runAll("task-B")

  assert_true(success == false, "Not all tasks succeeded")
