    }

    i = i + 1
  }

  return true
}

fn findDownstream(completed_task_id) {
  let i = 1
  while i <= GLOBAL_TASK_GRAPH_COUNT {
    let dep_count = Graph_getDependencyCount(i)

    let j = 1
    while j <= dep_count {
      let dep_id = Graph_getDependency(i, j)

      if dep_id == completed_task_id {
        if isReady(i) {
