fn ParallelExecutor_initialize(graph_task_count, max_parallel, failure_policy) {
  GLOBAL_TASK_GRAPH_COUNT = graph_task_count
  GLOBAL_MAX_PARALLEL = max_parallel
  GLOBAL_FAILURE_POLICY = failure_policy
  GLOBAL_EXECUTION_POOL_COUNT = 0
  GLOBAL_READY_QUEUE_COUNT = 0
  GLOBAL_COMPLETED_COUNT = 0
  GLOBAL_ERROR_DETECTED = false

  // 모든 Task 상태 Pending으로 초기화
  let i = 1
  while i <= graph_task_count {
    Task_setStatus(i, TASK_STATUS_PENDING)

    // 의존성 없으면 Ready
    if isReady(i) {
      let task_id = Graph_getTaskId(i)
      ReadyQueue_add(task_id)
      Task_setStatus(i, TASK_STATUS_READY)
    }

    i = i + 1
  }

  return true
}

fn ParallelExecutor_runAll(should_fail_task_id) {
  let max_iterations = 100
  let iteration = 0

  while ReadyQueue_length() > 0 {
    if iteration >= max_iterations {
      return false
    }

    // ExecutionPool에 공간이 있을 때까지 ReadyQueue에서 Task 가져오기
    while ReadyQueue_length() > 0 {
      if ExecutionPool_isFull() {
        break
      }

      let task_id = ReadyQueue_dequeue()

      if task_id == "" {
        break
      }

      let should_fail = (task_id == should_fail_task_id)
      let spawned = spawn(task_id, should_fail)

      if spawned == false {
        // Spawn 실패 (pool full)
        break
      }

      if GLOBAL_ERROR_DETECTED && GLOBAL_FAILURE_POLICY == POLICY_FAIL_FAST {
        return false
      }
    }

    iteration = iteration + 1
  }

  // 모든 Task 완료 확인
  let all_done = (GLOBAL_COMPLETED_COUNT == GLOBAL_TASK_GRAPH_COUNT)

  if all_done && GLOBAL_ERROR_DETECTED == false {
    return true
  } else {
    if GLOBAL_ERROR_DETECTED == false {
      return false
    }
    // Error detected but failure_policy permits continuation
    if GLOBAL_FAILURE_POLICY == POLICY_FAIL_CONTINUE {
      return false  // Still fail if not all completed
    }
  }

  return false
}

